"""Simple command-line argument parser."""
from dataclasses import dataclass, field
from typing import Any, Dict, List, Optional


@dataclass
class FlagDef:
    name: str
    short: str = ""
    type: type = str
    default: Any = None
    help: str = ""


class ParseResult:
    def __init__(self):
        self._values: Dict[str, Any] = {}

    def __getattr__(self, name: str) -> Any:
        if name.startswith('_'):
            return super().__getattribute__(name)
        return self._values.get(name)

    def __repr__(self):
        return f"ParseResult({self._values})"


class ArgParser:
    def __init__(self, description: str = ""):
        self.description = description
        self._positionals: List[str] = []
        self._flags: List[FlagDef] = []

    def add_positional(self, name: str) -> None:
        self._positionals.append(name)

    def add_flag(self, name: str, short: str = "",
                 type: type = str, default: Any = None,
                 help: str = "") -> None:
        self._flags.append(FlagDef(name, short, type, default, help))

    def parse(self, args: List[str]) -> ParseResult:
        result = ParseResult()
        # Set defaults
        for flag in self._flags:
            result._values[flag.name] = flag.default

        positional_idx = 0
        i = 0
        while i < len(args):
            arg = args[i]
            if arg.startswith('--'):
                name = arg[2:]
                flag = self._find_flag(name)
                if flag and flag.type == bool:
                    result._values[flag.name] = True
                elif flag and i + 1 < len(args):
                    result._values[flag.name] = flag.type(args[i + 1])
                    i += 1
            elif arg.startswith('-') and len(arg) == 2:
                flag = self._find_flag_short(arg[1:])
                if flag and flag.type == bool:
                    result._values[flag.name] = True
                elif flag and i + 1 < len(args):
                    result._values[flag.name] = flag.type(args[i + 1])
                    i += 1
            else:
                if positional_idx < len(self._positionals):
                    name = self._positionals[positional_idx]
                    result._values[name] = arg
                    positional_idx += 1
            i += 1
        return result

    def _find_flag(self, name: str) -> Optional[FlagDef]:
        return next((f for f in self._flags if f.name == name), None)

    def _find_flag_short(self, short: str) -> Optional[FlagDef]:
        return next((f for f in self._flags if f.short == short), None)
